test_cases.assertion_pseudocode:
content = readFile('docs/api.md')
for endpoint in ['POST /api/v1/workspaces', 'GET /api/v1/workspaces', 'GET /api/v1/workspaces/:slug', 'PATCH /api/v1/workspaces/:slug', 'archive', 'reactivate', 'DELETE /api/v1/workspaces/:slug']:
  assert endpoint in content or endpointAlias(endpoint) in content

content = readFile('docs/api.md')
for section in ['login', 'user', 'keys', 'tokens', 'orgs', 'admin']:
  assert section in content.lower()

content = readFile('docs/cli.md')
for cmd in ['create', 'list', 'get', 'update', 'archive', 'reactivate', 'delete']:
  assert f'workspace {cmd}' in content or f'afc workspace {cmd}' in content

content = readFile('docs/cli.md')
for cmd in ['login', 'user', 'keys', 'tokens', 'orgs', 'admin']:
  assert cmd in content.lower()

property_tests.invariant_check:
assert response.description is not None
assert isinstance(response.description, str)
if providedDescription is not None:
  assert response.description == providedDescription
else:
  assert response.description == ''

for pat in [patRead, patCreate]:
  listResp = GET('/api/v1/workspaces', auth=pat)
  assert listResp.status == 200
  getResp = GET('/api/v1/workspaces/' + ownedSlug, auth=pat)
  assert getResp.status == 200
  // Mutation endpoints must still be denied
  for mutationResp in [PATCH('/api/v1/workspaces/' + ownedSlug, body={description:'x'}, auth=pat),
                        POST('/api/v1/workspaces/' + ownedSlug + '/archive', auth=pat)]:
    assert mutationResp.status == 404
